static inline void fatal_cuda(cudaError_t error, int line_no) {
    if (error != cudaSuccess) {
        printf("Error at line %d: %s\n", line_no, cudaGetErrorString(error));
        exit((int)error);
    }
}

#define CUDA_CHECK(call) fatal_cuda((call), __LINE__)
#define CUDA_CHECK_LAST() fatal_cuda(cudaGetLastError(), __LINE__)

#ifdef TIMING
static inline void tvsub(struct timeval* x, struct timeval* y, struct timeval* diff) {
    diff->tv_sec = x->tv_sec - y->tv_sec;
    diff->tv_usec = x->tv_usec - y->tv_usec;
    if (diff->tv_usec < 0) {
        diff->tv_usec += 1000000;
        diff->tv_sec -= 1;
    }
}
