extern "C" void
kernel_gpu_opencl_wrapper(fp* image,
                          int Nr,
                          int Nc,
                          long Ne,
                          int niter,
                          fp lambda,
                          long NeROI,
                          int* iN,
                          int* iS,
                          int* jE,
                          int* jW,
                          int iter,
                          int mem_size_i,
                          int mem_size_j) {

#ifdef TIMING
    struct timeval tv;
    struct timeval tv_total_start, tv_total_end;
    struct timeval tv_init_end;
    struct timeval tv_h2d_start, tv_h2d_end;
    struct timeval tv_d2h_start, tv_d2h_end;
    struct timeval tv_kernel_start, tv_kernel_end;
    struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0.0f, mem_alloc_time = 0.0f, h2d_time = 0.0f, kernel_time = 0.0f,
          d2h_time = 0.0f, close_time = 0.0f, total_time = 0.0f;

    gettimeofday(&tv_total_start, NULL);
#endif

    int selected_device = 0;
    int device_count = 0;
    cudaDeviceProp prop;

    CUDA_CHECK(cudaGetDeviceCount(&device_count));
    if (device_count <= 0) {
        printf("Error at line %d: no CUDA devices found\n", __LINE__);
        exit(1);
    }

    if (&device_id_inuse) {
        selected_device = device_id_inuse;
    }
    if (selected_device < 0 || selected_device >= device_count) {
        selected_device = 0;
    }

    CUDA_CHECK(cudaSetDevice(selected_device));
    CUDA_CHECK(cudaGetDeviceProperties(&prop, selected_device));

    printf("Platform: NVIDIA CUDA\n");
    printf("Device: %s\n", prop.name);

    printf("-----OpenCL Compiler Output-----\n");
    printf("--------------------------------\n");

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    int blocks_x;
    size_t mem_size = sizeof(fp) * (size_t)Ne;

    fp* d_I;
    int* d_iN;
    int* d_iS;
    int* d_jE;
    int* d_jW;
    fp* d_dN;
    fp* d_dS;
    fp* d_dW;
    fp* d_dE;
    fp* d_c;
    fp* d_sums;
    fp* d_sums2;

    CUDA_CHECK(cudaMalloc((void**)&d_I, mem_size));

    CUDA_CHECK(cudaMalloc((void**)&d_iN, (size_t)mem_size_i));
    CUDA_CHECK(cudaMalloc((void**)&d_iS, (size_t)mem_size_i));
    CUDA_CHECK(cudaMalloc((void**)&d_jE, (size_t)mem_size_j));
    CUDA_CHECK(cudaMalloc((void**)&d_jW, (size_t)mem_size_j));

    CUDA_CHECK(cudaMalloc((void**)&d_dN, mem_size));
    CUDA_CHECK(cudaMalloc((void**)&d_dS, mem_size));
    CUDA_CHECK(cudaMalloc((void**)&d_dW, mem_size));
    CUDA_CHECK(cudaMalloc((void**)&d_dE, mem_size));

    CUDA_CHECK(cudaMalloc((void**)&d_c, mem_size));

    CUDA_CHECK(cudaMalloc((void**)&d_sums, mem_size));
    CUDA_CHECK(cudaMalloc((void**)&d_sums2, mem_size));

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    gettimeofday(&tv_h2d_start, NULL);
#endif

    CUDA_CHECK(cudaMemcpy(d_I, image, mem_size, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_iN, iN, (size_t)mem_size_i, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_iS, iS, (size_t)mem_size_i, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_jE, jE, (size_t)mem_size_j, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_jW, jW, (size_t)mem_size_j, cudaMemcpyHostToDevice));

#ifdef TIMING
    gettimeofday(&tv_h2d_end, NULL);
    tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
    h2d_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    blocks_x = (int)(Ne / NUMBER_THREADS);
    if (Ne % NUMBER_THREADS != 0) {
        blocks_x = blocks_x + 1;
    }

    printf("max # of workgroups = %d, # of threads/workgroup = %d (ensure that device can handle)\n",
           blocks_x, NUMBER_THREADS);

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    extract_kernel<<<blocks_x, NUMBER_THREADS>>>(Ne, d_I);
    CUDA_CHECK_LAST();

#ifdef TIMING
    CUDA_CHECK(cudaDeviceSynchronize());
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    int blocks2_x;
    int blocks2_work_size;
    long no;
    int mul;
    int mem_size_single = sizeof(fp) * 1;
    fp total;
    fp total2;
    fp meanROI;
    fp meanROI2;
    fp varROI;
    fp q0sqr;
    (void)mem_size_single;

    printf("Iterations Progress: hidden");

    for (iter = 0; iter < niter; iter++) {

        fflush(NULL);

#ifdef TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif
        prepare_kernel<<<blocks_x, NUMBER_THREADS>>>(Ne, d_I, d_sums, d_sums2);
        CUDA_CHECK_LAST();
#ifdef TIMING
        CUDA_CHECK(cudaDeviceSynchronize());
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

        blocks2_work_size = blocks_x;
        no = Ne;
        mul = 1;

        while (blocks2_work_size != 0) {

#ifdef TIMING
            gettimeofday(&tv_kernel_start, NULL);
#endif
            reduce_kernel<<<blocks2_work_size, NUMBER_THREADS>>>(Ne, no, mul, d_sums, d_sums2);
            CUDA_CHECK_LAST();
#ifdef TIMING
            CUDA_CHECK(cudaDeviceSynchronize());
            gettimeofday(&tv_kernel_end, NULL);
            tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
            kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

            no = blocks2_work_size;
            if (blocks2_work_size == 1) {
                blocks2_work_size = 0;
            }
            else {
                mul = mul * NUMBER_THREADS;
                blocks2_x = blocks2_work_size / NUMBER_THREADS;
                if (blocks2_work_size % NUMBER_THREADS != 0) {
                    blocks2_x = blocks2_x + 1;
                }
                blocks2_work_size = blocks2_x;
            }
        }

#ifdef TIMING
        gettimeofday(&tv_d2h_start, NULL);
#endif
        CUDA_CHECK(cudaMemcpy(&total, d_sums, sizeof(fp), cudaMemcpyDeviceToHost));
        CUDA_CHECK(cudaMemcpy(&total2, d_sums2, sizeof(fp), cudaMemcpyDeviceToHost));
#ifdef TIMING
        gettimeofday(&tv_d2h_end, NULL);
        tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
        d2h_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

        meanROI = total / (fp)(NeROI);
        meanROI2 = meanROI * meanROI;
        varROI = (total2 / (fp)(NeROI)) - meanROI2;
        q0sqr = varROI / meanROI2;

#ifdef TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif
        srad_kernel<<<blocks_x, NUMBER_THREADS>>>(lambda,
                                                  Nr,
                                                  Nc,
                                                  Ne,
                                                  d_iN,
                                                  d_iS,
                                                  d_jE,
                                                  d_jW,
                                                  d_dN,
                                                  d_dS,
                                                  d_dE,
                                                  d_dW,
                                                  q0sqr,
                                                  d_c,
                                                  d_I);
        CUDA_CHECK_LAST();
#ifdef TIMING
        CUDA_CHECK(cudaDeviceSynchronize());
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif
        srad2_kernel<<<blocks_x, NUMBER_THREADS>>>(lambda,
                                                   Nr,
                                                   Nc,
                                                   Ne,
                                                   d_iN,
                                                   d_iS,
                                                   d_jE,
                                                   d_jW,
                                                   d_dN,
                                                   d_dS,
                                                   d_dE,
                                                   d_dW,
                                                   d_c,
                                                   d_I);
        CUDA_CHECK_LAST();
#ifdef TIMING
        CUDA_CHECK(cudaDeviceSynchronize());
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif
    }

    printf("\n");

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif
    compress_kernel<<<blocks_x, NUMBER_THREADS>>>(Ne, d_I);
    CUDA_CHECK_LAST();
    CUDA_CHECK(cudaDeviceSynchronize());
#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif
    CUDA_CHECK(cudaMemcpy(image, d_I, mem_size, cudaMemcpyDeviceToHost));
#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    CUDA_CHECK(cudaFree(d_I));
    CUDA_CHECK(cudaFree(d_c));

    CUDA_CHECK(cudaFree(d_iN));
    CUDA_CHECK(cudaFree(d_iS));
    CUDA_CHECK(cudaFree(d_jE));
    CUDA_CHECK(cudaFree(d_jW));

    CUDA_CHECK(cudaFree(d_dN));
    CUDA_CHECK(cudaFree(d_dS));
    CUDA_CHECK(cudaFree(d_dE));
    CUDA_CHECK(cudaFree(d_dW));

    CUDA_CHECK(cudaFree(d_sums));
    CUDA_CHECK(cudaFree(d_sums2));

#ifdef TIMING
    printf("Time spent in different stages of the application:\n");
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    gettimeofday(&tv_total_end, NULL);
    tvsub(&tv_total_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}
